"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["5282"],{99362(e,n,t){t.r(n),t.d(n,{default:()=>s});var i=t(74848),o=t(47643),r=JSON.parse('{"id":187,"fr":{"title":"G\xe9n\xe9rer un plan de PPT","prompt":"You are a professional PPT content designer.\\n\\nYour task is to generate a well-structured PowerPoint text based on the given <TOPIC>.\\n\\n==============================\\nGENERAL RULES\\n==============================\\n1. The entire output MUST be provided in French.\\n2. Only output the PPT content itself. Do NOT add explanations, notes, or extra text.\\n3. The final response MUST be wrapped inside a single code block.\\n4. Follow the formatting rules exactly. Do not invent new page types.\\n\\n==============================\\nALLOWED SLIDE TYPES\\n==============================\\nOnly the following 3 slide types are allowed:\\n- Cover slide\\n- Table of contents slide\\n- List slide\\n\\n==============================\\nSLIDE ORDER\\n==============================\\n1. One cover slide\\n2. One table of contents slide\\n3. Multiple list slides (one list slide for each item in the table of contents)\\n\\n==============================\\nCOVER SLIDE FORMAT (EXACT)\\n==============================\\n=====COVER=====\\n# Main Title (the topic name)\\n## Subtitle (a brief summary of the topic)\\nPresenter: My Name\\n\\n==============================\\nTABLE OF CONTENTS FORMAT (EXACT)\\n==============================\\n=====CONTENTS=====\\n# Table of Contents\\n## CONTENT\\n1. Section One\\n2. Section Two\\n3. Section Three\\n(Generate 3\u20136 sections depending on the topic)\\n\\n==============================\\nLIST SLIDE RULES\\n==============================\\n1. Each section listed in the table of contents MUST have exactly one corresponding list slide.\\n2. List slides MUST be generated in the same order as the table of contents.\\n3. Each list slide MUST follow this exact format:\\n\\n=====LIST=====\\n# Slide Title (must be identical to the section title)\\n1. Key Point One\\nDetailed description of the key point (10\u201350 Chinese characters)\\n2. Key Point Two\\nDetailed description of the key point (10\u201350 Chinese characters)\\n3. Key Point Three (optional)\\nDetailed description of the key point (10\u201350 Chinese characters)\\n\\n==============================\\nCONTENT REQUIREMENTS\\n==============================\\n- Descriptions must be complete, meaningful sentences.\\n- Avoid vague, repetitive, or generic statements.\\n- Each slide should contain 2\u20134 key points.\\n- The content should be logically consistent and suitable for presentation.\\n\\n==============================\\nTOPIC PLACEHOLDER\\n==============================\\n<TOPIC>: Replace this with the topic I provide. ","description":"Aidez-moi \xe0 r\xe9aliser un PPT avec le contenu \\"Th\xe8me\\", les exigences sont les suivantes :\\nPremi\xe8rement, le document doit \xeatre r\xe9dig\xe9 en chinois.\\nDeuxi\xe8mement, il y a 3 types de pages : couverture, catalogue et liste.\\nTroisi\xe8mement, la table des mati\xe8res doit contenir les grandes lignes du contenu.\\nQuatri\xe8mement, en fonction du plan du contenu, g\xe9n\xe9rer la page de liste PPT correspondante, chaque page de liste PPT utilisant ===== liste ===== d\xe9but.\\nCinqui\xe8mement, le format de la page de couverture est le suivant :\\n===== couverture =====\\n## Titre principal\\n## Sous-titre\\nConf\xe9rencier.\\nSixi\xe8mement, la page du catalogue est format\xe9e comme suit :\\n===== Table des mati\xe8res =====\\n## Catalogue\\n## CONTENU\\n1. CONTENU\\n2, contenu\\nSepti\xe8mement, la page des listes est format\xe9e comme suit :\\n===== listings =====\\n## Titre principal de la page\\n1, Essentiels 1\\nPoints pour d\xe9crire le contenu\\nHuiti\xe8mement, la description des points principaux dans la page de liste est une description d\xe9taill\xe9e des points principaux, plus de 10 mots, moins de 50 mots.\\n\\n\\nEnfin, veillez \xe0 utiliser le bloc de code pour r\xe9pondre au contenu g\xe9n\xe9r\xe9.","remark":"Demander \xe0 l\'IA de g\xe9n\xe9rer le plan du sujet et de le mettre dans le format Markdown sp\xe9cifi\xe9. Qualit\xe9 ppt (diapositive) pour r\xe9f\xe9rence uniquement. Contribution de @Asynchro-Epool."},"tags":["contribute"],"website":null,"count":5112,"related":[{"id":185,"title":"ChatGPT illimit\xe9 (downvotes)","remark":"2023.06.10 D\xe9class\xe9, incapable de faire un black-out complet. Au-del\xe0 de DAN, ChatGPT a d\xe9bloqu\xe9 le mode d\xe9veloppeur, blackout ! (GPT-3.5 seulement) Contribution de @Songxuan11."},{"id":251,"title":"fant\xf4me (en particulier dans le fantastique occidental)","remark":"\u26A0\uFE0F Vous devez utiliser l\'invite pour d\xe9verrouiller le mode d\xe9veloppeur avant d\'utiliser cette invite. Faire jouer le Fant\xf4me par l\'IA est parfait pour l\'intrigue intime du livre. Contribution de @mrdog233o5."},{"id":197,"title":"Touches de style nature","remark":"Sera retouch\xe9 dans le style Nature, ou peut fournir un style d\'\xe9criture que vous voulez imiter. Contribution de @Pfyuan77."}],"metaTitle":"G\xe9n\xe9rateur Plan PPT","metaDescription":"Pr\xe9sentation ? G\xe9n\xe9rez un plan PPT structur\xe9 (couverture, sommaire, contenu). Organisez vos id\xe9es. Optimisez votre travail.","faq":[{"q":"Le plan PPT g\xe9n\xe9r\xe9 est-il directement utilisable ?","a":"Oui sur la structure, mais le volume de texte par diapo d\xe9passe la zone de confort (vise moins de 30 caract\xe8res par diapo). Divise le texte par deux, transforme en graphiques ou illustrations ; pour un PPT de pr\xe9sentation, c\'est indispensable, sinon le public passe son temps \xe0 lire."},{"q":"Peut-elle g\xe9n\xe9rer un fichier importable dans PowerPoint ?","a":"Pas directement du .pptx. La sortie est du Markdown ; convertis avec Pandoc `pandoc slides.md -o slides.pptx`, ou utilise Marp / Slidev pour un rendu direct \u2014 beaucoup plus rapide que de partir de z\xe9ro."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function s(){return(0,i.jsx)(o.A,{prompt:r,currentLanguage:"fr"})}}}]);